extension CurrencyExtension on Currency {
  String get code {
    switch (this) {
      case Currency.usd: return 'USD';
      case Currency.eur: return 'EUR';
      case Currency.gbp: return 'GBP';
      case Currency.jpy: return 'JPY';
      case Currency.cad: return 'CAD';
      case Currency.aud: return 'AUD';
    }
  }

  String get symbol {
    switch (this) {
      case Currency.usd: return '\$';
      case Currency.eur: return '€';
      case Currency.gbp: return '£';
      case Currency.jpy: return '¥';
      case Currency.cad: return 'C\$';
      case Currency.aud: return 'A\$';
    }
  }

  int get decimalPlaces {
    switch (this) {
      case Currency.jpy: return 0;
      default: return 2;
    }
  }
}

class PaymentAmount {
  final int amountInSmallestUnit; // cents, pence, etc.
  final Currency currency;

  const PaymentAmount({
    required this.amountInSmallestUnit,
    required this.currency,
  });

  double get displayAmount =>
      amountInSmallestUnit / (currency.decimalPlaces == 0 ? 1 : 100);

  String get formatted =>
      '${currency.symbol}${displayAmount.toStringAsFixed(currency.decimalPlaces)}';

  Map<String, dynamic> toJson() => {
    'amount': amountInSmallestUnit,
    'currency': currency.code,
  };

  factory PaymentAmount.fromJson(Map<String, dynamic> json) {
    return PaymentAmount(
      amountInSmallestUnit: json['amount'] as int,
      currency: Currency.values.firstWhere(
        (c) => c.code == json['currency'],
        orElse: () => Currency.usd,
      ),
    );
  }
}

