class PaymentSecurity {
  static final PaymentSecurity _instance = PaymentSecurity._internal();
  factory PaymentSecurity() => _instance;
  PaymentSecurity._internal();

  late encrypt_lib.Key _encryptionKey;
  late encrypt_lib.IV _iv;
  late encrypt_lib.Encrypter _encrypter;
  bool _initialized = false;

  Future<void> initialize(String encryptionKeyBase64) async {
    _encryptionKey = encrypt_lib.Key.fromBase64(encryptionKeyBase64);
    _iv = encrypt_lib.IV.fromLength(16);
    _encrypter = encrypt_lib.Encrypter(encrypt_lib.AES(_encryptionKey));
    _initialized = true;
  }

  void _ensureInitialized() {
    if (!_initialized) {
      throw StateError('PaymentSecurity not initialized. Call initialize() first.');
    }
  }

  String encryptSensitiveData(String data) {
    _ensureInitialized();
    return _encrypter.encrypt(data, iv: _iv).base64;
  }

  String decryptSensitiveData(String encryptedData) {
    _ensureInitialized();
    return _encrypter.decrypt64(encryptedData, iv: _iv);
  }

  String hashData(String data) {
    final bytes = utf8.encode(data);
    return sha256.convert(bytes).toString();
  }

  String generateIdempotencyKey() {
    return const Uuid().v4();
  }

  String generateTransactionId() {
    final timestamp = DateTime.now().millisecondsSinceEpoch;
    final uuid = const Uuid().v4().replaceAll('-', '').substring(0, 12);
    return 'txn_${timestamp}_$uuid';
  }

  bool validateCardNumber(String cardNumber) {
    final sanitized = cardNumber.replaceAll(RegExp(r'\s|-'), '');
    if (sanitized.length < 13 || sanitized.length > 19) return false;
    if (!RegExp(r'^\d+$').hasMatch(sanitized)) return false;
    return _luhnCheck(sanitized);
  }

  bool _luhnCheck(String number) {
    int sum = 0;
    bool alternate = false;
    for (int i = number.length - 1; i >= 0; i--) {
      int digit = int.parse(number[i]);
      if (alternate) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }
      sum += digit;
      alternate = !alternate;
    }
    return sum % 10 == 0;
  }

  bool validateCVV(String cvv) {
    return RegExp(r'^\d{3,4}$').hasMatch(cvv);
  }

  bool validateExpiry(int month, int year) {
    if (month < 1 || month > 12) return false;
    final now = DateTime.now();
    final expiry = DateTime(year, month + 1, 0);
    return expiry.isAfter(now);
  }

  String detectCardBrand(String cardNumber) {
    final sanitized = cardNumber.replaceAll(RegExp(r'\s|-'), '');
    if (sanitized.startsWith('4')) return 'visa';
    if (RegExp(r'^5[1-5]').hasMatch(sanitized)) return 'mastercard';
    if (RegExp(r'^3[47]').hasMatch(sanitized)) return 'amex';
    if (RegExp(r'^6(?:011|5)').hasMatch(sanitized)) return 'discover';
    if (RegExp(r'^35(?:2[89]|[3-8])').hasMatch(sanitized)) return 'jcb';
    if (RegExp(r'^3(?:0[0-5]|[68])').hasMatch(sanitized)) return 'diners';
    return 'unknown';
  }

  String maskCardNumber(String cardNumber) {
    final sanitized = cardNumber.replaceAll(RegExp(r'\s|-'), '');
    if (sanitized.length < 4) return sanitized;
    final lastFour = sanitized.substring(sanitized.length - 4);
    return '**** **** **** $lastFour';
  }

  Map<String, String> generateSecureHeaders(String apiKey, String payload) {
    final timestamp = DateTime.now().millisecondsSinceEpoch.toString();
    final signature = _generateSignature(payload, timestamp, apiKey);
    return {
      'X-Timestamp': timestamp,
      'X-Signature': signature,
      'X-Idempotency-Key': generateIdempotencyKey(),
      'Content-Type': 'application/json',
    };
  }

  String _generateSignature(String payload, String timestamp, String secretKey) {
    final data = '$timestamp.$payload';
    final key = utf8.encode(secretKey);
    final bytes = utf8.encode(data);
    final hmacSha256 = Hmac(sha256, key);
    return hmacSha256.convert(bytes).toString();
  }
}

