class StripeGateway implements PaymentGateway {
  String? _publishableKey;
  String? _secretKey;
  bool _initialized = false;
  final PaymentSecurity _security = PaymentSecurity();
  final String _baseUrl = 'https://api.stripe.com/v1';

  @override
  String get name => 'Stripe';

  @override
  bool get isInitialized => _initialized;

  @override
  Future<void> initialize(Map<String, String> configuration) async {
    _publishableKey = configuration['publishable_key'];
    _secretKey = configuration['secret_key'];

    if (_publishableKey == null || _secretKey == null) {
      throw ArgumentError('Stripe requires publishable_key and secret_key');
    }

    _initialized = true;
  }

  @override
  Future<PaymentResult> processPayment(PaymentTransaction transaction) async {
    _ensureInitialized();

    try {
      // In production, this would make actual API calls to Stripe
      // Here we simulate the payment intent creation flow
      final paymentIntentData = {
        'amount': transaction.amount.amountInSmallestUnit,
        'currency': transaction.amount.currency.code.toLowerCase(),
        'payment_method': _mapPaymentMethod(transaction.method),
        'confirm': true,
        'metadata': {
          'transaction_id': transaction.transactionId,
          'customer_id': transaction.customerId,
          ...?transaction.metadata,
        },
      };

      // Simulate API call
      await Future.delayed(const Duration(milliseconds: 500));

      // Simulate successful response
      final completedTransaction = transaction.copyWith(
        status: PaymentStatus.completed,
        externalTransactionId: 'pi_${_security.generateIdempotencyKey()}',
        completedAt: DateTime.now(),
        receiptUrl: 'https://pay.stripe.com/receipts/${transaction.transactionId}',
      );

      return PaymentResult.success(completedTransaction);
    } catch (e) {
      return PaymentResult.failure('stripe_error', e.toString());
    }
  }

  @override
  Future<PaymentResult> refundPayment(String transactionId, PaymentAmount? amount) async {
    _ensureInitialized();

    try {
      await Future.delayed(const Duration(milliseconds: 300));

      final refundTransaction = PaymentTransaction(
        transactionId: _security.generateTransactionId(),
        externalTransactionId: 're_${_security.generateIdempotencyKey()}',
        amount: amount ?? const PaymentAmount(amountInSmallestUnit: 0, currency: Currency.usd),
        method: PaymentMethod.creditCard,
        status: PaymentStatus.refunded,
        createdAt: DateTime.now(),
        completedAt: DateTime.now(),
        metadata: {'original_transaction_id': transactionId},
      );

      return PaymentResult.success(refundTransaction);
    } catch (e) {
      return PaymentResult.failure('refund_error', e.toString());
    }
  }

  @override
  Future<PaymentTransaction?> getTransactionStatus(String transactionId) async {
    _ensureInitialized();
    await Future.delayed(const Duration(milliseconds: 200));
    return null;
  }

  @override
  Future<String> tokenizeCard(Map<String, String> cardData) async {
    _ensureInitialized();

    // PCI Compliance: validate we're not storing raw card data
    PCIComplianceManager().validateDataHandling(
      operation: 'tokenization',
      data: cardData,
    );

    await Future.delayed(const Duration(milliseconds: 300));
    return 'tok_${_security.generateIdempotencyKey()}';
  }

  @override
  Future<void> dispose() async {
    _initialized = false;
  }

  String _mapPaymentMethod(PaymentMethod method) {
    switch (method) {
      case PaymentMethod.creditCard:
      case PaymentMethod.debitCard:
        return 'card';
      case PaymentMethod.applePay:
        return 'apple_pay';
      case PaymentMethod.googlePay:
        return 'google_pay';
      default:
        return 'card';
    }
  }

  void _ensureInitialized() {
    if (!_initialized) {
      throw StateError('StripeGateway not initialized');
    }
  }
}

