  InAppPurchaseService._internal();

  bool _initialized = false;
  final List<InAppProduct> _availableProducts = [];
  final List<String> _purchasedProductIds = [];
  final _purchaseController = StreamController<PurchaseEvent>.broadcast();

  Stream<PurchaseEvent> get purchaseStream => _purchaseController.stream;
  List<InAppProduct> get availableProducts => List.unmodifiable(_availableProducts);
  bool get isInitialized => _initialized;

  Future<void> initialize() async {
    // In production, initialize in_app_purchase plugin
    _initialized = true;
  }

  Future<List<InAppProduct>> loadProducts(List<String> productIds) async {
    _ensureInitialized();

    // In production, query the app store for products
    await Future.delayed(const Duration(milliseconds: 500));

    // Simulated products
    _availableProducts.clear();
    _availableProducts.addAll([
      InAppProduct(
        productId: 'premium_monthly',
        title: 'Premium Monthly',
        description: 'Full access for one month',
        price: const PaymentAmount(amountInSmallestUnit: 999, currency: Currency.usd),
        isSubscription: true,
        subscriptionPeriod: 'P1M',
      ),
      InAppProduct(
        productId: 'premium_yearly',
        title: 'Premium Yearly',
        description: 'Full access for one year',
        price: const PaymentAmount(amountInSmallestUnit: 9999, currency: Currency.usd),
        isSubscription: true,
        subscriptionPeriod: 'P1Y',
      ),
      InAppProduct(
        productId: 'coins_100',
        title: '100 Coins',
        description: 'Bundle of 100 in-app coins',
        price: const PaymentAmount(amountInSmallestUnit: 499, currency: Currency.usd),
        isConsumable: true,
      ),
      InAppProduct(
        productId: 'coins_500',
        title: '500 Coins',
        description: 'Bundle of 500 in-app coins',
        price: const PaymentAmount(amountInSmallestUnit: 1999, currency: Currency.usd),
        isConsumable: true,
      ),
    ]);

    return _availableProducts;
  }

  Future<PaymentResult> purchaseProduct(String productId) async {
    _ensureInitialized();

    final product = _availableProducts.firstWhere(
      (p) => p.productId == productId,
      orElse: () => throw ArgumentError('Product not found: $productId'),
    );

    _purchaseController.add(PurchaseEvent(
      type: PurchaseEventType.started,
      productId: productId,
    ));

    try {
      // Simulate purchase flow
      await Future.delayed(const Duration(seconds: 1));

      final security = PaymentSecurity();
      final transaction = PaymentTransaction(
        transactionId: security.generateTransactionId(),
        externalTransactionId: 'iap_${security.generateIdempotencyKey()}',
        amount: product.price,
        method: PaymentMethod.inAppPurchase,
        status: PaymentStatus.completed,
        createdAt: DateTime.now(),
        completedAt: DateTime.now(),
        metadata: {
          'product_id': productId,
          'is_consumable': product.isConsumable,
          'is_subscription': product.isSubscription,
          'platform': Platform.isIOS ? 'ios' : 'android',
        },
      );

      _purchasedProductIds.add(productId);

      _purchaseController.add(PurchaseEvent(
        type: PurchaseEventType.completed,
        productId: productId,
        transaction: transaction,
      ));

      // Verify receipt server-side
      await _verifyReceipt(transaction);

      return PaymentResult.success(transaction);
    } catch (e) {
      _purchaseController.add(PurchaseEvent(
        type: PurchaseEventType.failed,
        productId: productId,
        error: e.toString(),
      ));
      return PaymentResult.failure('iap_error', e.toString());
    }
  }

  Future<void> restorePurchases() async {
    _ensureInitialized();

    _purchaseController.add(PurchaseEvent(
      type: PurchaseEventType.restoreStarted,
      productId: '',
    ));

    await Future.delayed(const Duration(seconds: 1));

    _purchaseController.add(PurchaseEvent(
      type: PurchaseEventType.restoreCompleted,
      productId: '',
    ));
  }

  bool isPurchased(String productId) => _purchasedProductIds.contains(productId);

  Future<void> _verifyReceipt(PaymentTransaction transaction) async {
    // In production, send receipt to your backend for verification
    // Your backend should verify with Apple/Google servers
    await Future.delayed(const Duration(milliseconds: 200));
  }

  void _ensureInitialized() {
    if (!_initialized) {
      throw StateError('InAppPurchaseService not initialized');
    }
  }

  Future<void> dispose() async {
    await _purchaseController.close();
    _initialized = false;
  }
}

enum PurchaseEventType {
  started,
  completed,
  failed,
  cancelled,
  restoreStarted,
  restoreCompleted,
}

class PurchaseEvent {
  final PurchaseEventType type;
  final String productId;
  final PaymentTransaction? transaction;
  final String? error;

  const PurchaseEvent({
    required this.type,
    required this.productId,
    this.transaction,
    this.error,
  });
}

