// lib/payment/services/transaction_manager.dart
// ============================================

class TransactionManager {
  static final TransactionManager _instance = TransactionManager._internal();
  factory TransactionManager() => _instance;
  TransactionManager._internal();

  final Map<String, PaymentTransaction> _transactions = {};
  final _transactionController = StreamController<PaymentTransaction>.broadcast();
  final _retryQueue = <String, int>{};
  static const int _maxRetries = 3;

  Stream<PaymentTransaction> get transactionStream => _transactionController.stream;

  void addTransaction(PaymentTransaction transaction) {
    PCIComplianceManager().validateDataHandling(
      operation: 'store_transaction',
      data: transaction.toJson().map((k, v) => MapEntry(k, v?.toString() ?? '')),
    );

    _transactions[transaction.transactionId] = transaction;
    _transactionController.add(transaction);
  }

  void updateTransaction(PaymentTransaction transaction) {
    _transactions[transaction.transactionId] = transaction;
    _transactionController.add(transaction);
  }

  PaymentTransaction? getTransaction(String transactionId) {
    return _transactions[transactionId];
  }

  List<PaymentTransaction> getTransactionsByStatus(PaymentStatus status) {
    return _transactions.values.where((t) => t.status == status).toList();
  }

  List<PaymentTransaction> getTransactionsByCustomer(String customerId) {
    return _transactions.values.where((t) => t.customerId == customerId).toList();
  }

  List<PaymentTransaction> getRecentTransactions({int limit = 50}) {
    final sorted = _transactions.values.toList()
      ..sort((a, b) => b.createdAt.compareTo(a.createdAt));
    return sorted.take(limit).toList();
  }

  Future<PaymentResult> processWithRetry(
    PaymentGateway gateway,
    PaymentTransaction transaction,
  ) async {
    final txnId = transaction.transactionId;
    _retryQueue[txnId] = 0;

    while ((_retryQueue[txnId] ?? 0) < _maxRetries) {
      try {
        addTransaction(transaction.copyWith(status: PaymentStatus.processing));
        final result = await gateway.processPayment(transaction);

        if (result.success) {
          if (result.transaction != null) {
            updateTransaction(result.transaction!);
          }
          _retryQueue.remove(txnId);
          return result;
        }

        if (result.requiresAction) {
          _retryQueue.remove(txnId);
          return result;
        }

        // Non-retryable errors
        if (_isNonRetryableError(result.errorCode)) {
          updateTransaction(transaction.copyWith(
            status: PaymentStatus.failed,
            errorMessage: result.errorMessage,
          ));
          _retryQueue.remove(txnId);
          return result;
        }

        _retryQueue[txnId] = (_retryQueue[txnId] ?? 0) + 1;

        if ((_retryQueue[txnId] ?? 0) < _maxRetries) {
          final delay = Duration(milliseconds: 1000 * (_retryQueue[txnId] ?? 1));
          await Future.delayed(delay);
        }
      } catch (e) {
        _retryQueue[txnId] = (_retryQueue[txnId] ?? 0) + 1;
        if ((_retryQueue[txnId] ?? 0) >= _maxRetries) {
          updateTransaction(transaction.copyWith(
            status: PaymentStatus.failed,
            errorMessage: 'Max retries exceeded: ${e.toString()}',
          ));
          _retryQueue.remove(txnId);
          return PaymentResult.failure('max_retries', e.toString());
        }
        await Future.delayed(Duration(milliseconds: 1000 * (_retryQueue[txnId] ?? 1)));
      }
    }

    _retryQueue.remove(txnId);
    return PaymentResult.failure('max_retries', 'Payment processing failed after $_maxRetries attempts');
  }

  bool _isNonRetryableError(String? errorCode) {
    const nonRetryable = [
      'card_declined',
      'insufficient_funds',
      'invalid_card',
      'expired_card',
      'fraud_detected',
      'authentication_required',
    ];
    return nonRetryable.contains(errorCode);
  }

  TransactionSummary getSummary({DateTime? from, DateTime? to}) {
    var transactions = _transactions.values.toList();

    if (from != null) {
      transactions = transactions.where((t) => t.createdAt.isAfter(from)).toList();
    }
    if (to != null) {
      transactions = transactions.where((t) => t.createdAt.isBefore(to)).toList();
    }

    final completed = transactions.where((t) => t.status == PaymentStatus.completed);
    final failed = transactions.where((t) => t.status == PaymentStatus.failed);
    final refunded = transactions.where((t) => t.status == PaymentStatus.refunded);

    int totalRevenue = 0;
    for (final t in completed) {
      totalRevenue += t.amount.amountInSmallestUnit;
    }

    int totalRefunded = 0;
    for (final t in refunded) {
      totalRefunded += t.amount.amountInSmallestUnit;
    }

    return TransactionSummary(
      totalTransactions: transactions.length,
      completedCount: completed.length,
      failedCount: failed.length,
      refundedCount: refunded.length,
      totalRevenue: totalRevenue,
      totalRefunded: totalRefunded,
      netRevenue: totalRevenue - totalRefunded,
    );
  }

  Future<void> dispose() async {
    await _transactionController.close();
  }
}

class TransactionSummary {
  final int totalTransactions;
  final int completedCount;
  final int failedCount;
  final int refundedCount;
  final int totalRevenue;
  final int totalRefunded;
  final int netRevenue;

  const TransactionSummary({
    required this.totalTransactions,
    required this.completedCount,
    required this.failedCount,
    required this.refundedCount,
    required this.totalRevenue,
    required this.totalRefunded,
    required this.netRevenue,
  });
}

