class PaymentProcessorConfig {
  final String encryptionKey;
  final Map<String, String> stripeConfig;
  final Map<String, String>? braintreeConfig;
  final String defaultGateway;
  final bool enableApplePay;
  final bool enableGooglePay;
  final bool enableInAppPurchases;
  final bool isTestMode;

  const PaymentProcessorConfig({
    required this.encryptionKey,
    required this.stripeConfig,
    this.braintreeConfig,
    this.defaultGateway = 'stripe',
    this.enableApplePay = true,
    this.enableGooglePay = true,
    this.enableInAppPurchases = true,
    this.isTestMode = false,
  });
}

class PaymentProcessor {
  static PaymentProcessor? _instance;
  static PaymentProcessor get instance {
    if (_instance == null) {
      throw StateError('PaymentProcessor not initialized. Call initialize() first.');
    }
    return _instance!;
  }

  final PaymentSecurity _security = PaymentSecurity();
  final PCIComplianceManager _pciManager = PCIComplianceManager();
  final TransactionManager _transactionManager = TransactionManager();
  final InAppPurchaseService _iapService = InAppPurchaseService();
  final WalletService _walletService = WalletService();

  final Map<String, PaymentGateway> _gateways = {};
  late String _defaultGatewayName;
  late PaymentProcessorConfig _config;
  bool _initialized = false;

  PaymentProcessor._();

  static Future<PaymentProcessor> initialize(PaymentProcessorConfig config) async {
    _instance = PaymentProcessor._();
    await _instance!._init(config);
    return _instance!;
  }

  Future<void> _init(PaymentProcessorConfig config) async {
    _config = config;

    // Initialize security
    await _security.initialize(config.encryptionKey);

    // Enable PCI audit mode in test
    if (config.isTestMode) {
      _pciManager.enableAuditMode();
    }

    // Initialize Stripe
    final stripeGateway = StripeGateway();
    await stripeGateway.initialize(config.stripeConfig);
    _gateways['stripe'] = stripeGateway;

    // Initialize Braintree if configured
    if (config.braintreeConfig != null) {
      final braintreeGateway = BraintreeGateway();
      await braintreeGateway.initialize(config.braintreeConfig!);
      _gateways['braintree'] = braintreeGateway;
    }

    _defaultGatewayName = config.defaultGateway;

    // Initialize wallet services
    if (config.enableApplePay || config.enableGooglePay) {
      await _walletService.initialize();
    }

    // Initialize IAP
    if (config.enableInAppPurchases) {
      await _iapService.initialize();
    }

    _initialized = true;
  }

  // Getters
  bool get isInitialized => _initialized;
  TransactionManager get transactions => _transactionManager;
  InAppPurchaseService get inAppPurchases => _iapService;
  WalletService get wallet => _walletService;
  PaymentSecurity get security => _security;
  PCIComplianceManager get pciCompliance => _pciManager;

  bool get isApplePayAvailable => _walletService.isApplePayAvailable;
  bool get isGooglePayAvailable => _walletService.isGooglePayAvailable;

  PaymentGateway get _defaultGateway {
    final gateway = _gateways[_defaultGatewayName];
    if (gateway == null) throw StateError('Default gateway not found');
    return gateway;
  }

  // ---- Card Payment ----

  Future<PaymentResult> processCardPayment({
    required PaymentAmount amount,
    required String cardToken,
    String? customerId,
    String? description,
    Map<String, dynamic>? metadata,
    String? gatewayName,
  }) async {
    _ensureInitialized();

    final transaction = PaymentTransaction(
      transactionId: _security.generateTransactionId(),
      amount: amount,
      method: PaymentMethod.creditCard,
      status: PaymentStatus.pending,
      createdAt: DateTime.now(),
      customerId: customerId,
      description: description,
      metadata: {
        'card_token': cardToken,
        ...?metadata,
      },
    );

    final gateway = gatewayName != null ? _gateways[gatewayName] : _defaultGateway;
    if (gateway == null) {
      return PaymentResult.failure('invalid_gateway', 'Gateway "$gatewayName" not found');
    }

    return _transactionManager.processWithRetry(gateway, transaction);
  }

  // ---- Tokenize Card ----

  Future<CardTokenResult> tokenizeCard({
    required String cardNumber,
    required int expiryMonth,
    required int expiryYear,
    required String cvv,
    String? cardholderName,
    String? gatewayName,
  }) async {
    _ensureInitialized();

    // Validate card
    if (!_security.validateCardNumber(cardNumber)) {
      return CardTokenResult.failure('invalid_card_number', 'Invalid card number');
    }
    if (!_security.validateExpiry(expiryMonth, expiryYear)) {
      return CardTokenResult.failure('invalid_expiry', 'Card is expired or invalid expiry');
    }
    if (!_security.validateCVV(cvv)) {
      return CardTokenResult.failure('invalid_cvv', 'Invalid CVV');
    }

    final brand = _security.detectCardBrand(cardNumber);
    final lastFour = cardNumber.replaceAll(RegExp(r'\s|-'), '').substring(
      cardNumber.replaceAll(RegExp(r'\s|-'), '').length - 4,
    );

    final gateway = gatewayName != null ? _gateways[gatewayName] : _defaultGateway;
    if (gateway == null) {
      return CardTokenResult.failure('invalid_gateway', 'Gateway not found');
    }

    try {
      // PCI: Never send raw card number, tokenize immediately
      final token = await gateway.tokenizeCard({
        'number': _security.encryptSensitiveData(cardNumber),
        'exp_month': expiryMonth.toString(),
        'exp_year': expiryYear.toString(),
        'cvc': _security.encryptSensitiveData(cvv),
        'name': cardholderName ?? '',
      });

      final cardDetails = CardDetails(
        tokenizedNumber: token,
        lastFour: lastFour,
        brand: brand,
        expiryMonth: expiryMonth,
        expiryYear: expiryYear,
        cardholderName: cardholderName,
      );

      return CardTokenResult.success(token, cardDetails);
    } catch (e) {
      return CardTokenResult.failure('tokenization_error', e.toString());
    }
  }

  // ---- Apple Pay ----

  Future<PaymentResult> processApplePay({
    required PaymentAmount amount,
    required String merchantIdentifier,
    String countryCode = 'US',
    List<String> supportedNetworks = const ['visa', 'mastercard', 'amex'],
    String? description,
  }) async {
    _ensureInitialized();
    return _walletService.payWithApplePay(
      amount: amount,
      merchantIdentifier: merchantIdentifier,
      supportedNetworks: supportedNetworks,
      countryCode: countryCode,
      description: description,
    );
  }

  // ---- Google Pay ----

  Future<PaymentResult> processGooglePay({
    required PaymentAmount amount,
    required String merchantId,
    required String merchantName,
    required String gatewayName,
    required String gatewayMerchantId,
    String? description,
  }) async {
    _ensureInitialized();
    return _walletService.payWithGooglePay(
      amount: amount,
      merchantId: merchantId,
      merchantName: merchantName,
      gatewayName: gatewayName,
      gatewayMerchantId: gatewayMerchantId,
      description: description,
    );
  }

  // ---- In-App Purchases ----

  Future<List<InAppProduct>> loadProducts(List<String> productIds) async {
    _ensureInitialized();
    return _iapService.loadProducts(productIds);
  }

  Future<PaymentResult> purchaseProduct(String productId) async {
    _ensureInitialized();
    return _iapService.purchaseProduct(productId);
  }

  Future<void> restorePurchases() async {
    _ensureInitialized();
    return _iapService.restorePurchases();
  }

  // ---- Refunds ----

  Future<PaymentResult> refundPayment({
    required String transactionId,
    PaymentAmount? amount,
    String? gatewayName,
  }) async {
    _ensureInitialized();

    final gateway = gatewayName != null ? _gateways[gatewayName] : _defaultGateway;
    if (gateway == null) {
      return PaymentResult.failure('invalid_gateway', 'Gateway not found');
    }

    return gateway.refundPayment(transactionId, amount);
  }

  // ---- PCI Compliance ----

  PCIAssessmentResult runPCIAssessment() {
    return _pciManager.runSelfAssessment();
  }

  void _ensureInitialized() {
    if (!_initialized) {
      throw StateError('PaymentProcessor not initialized');
    }
  }

  Future<void> dispose() async {
    for (final gateway in _gateways.values) {
      await gateway.dispose();
    }
    await _transactionManager.dispose();
    await _iapService.dispose();
    _initialized = false;
    _instance = null;
  }
}

class CardTokenResult {
  final bool success;
  final String? token;
  final CardDetails? cardDetails;
  final String? errorCode;
  final String? errorMessage;

  const CardTokenResult({
    required this.success,
    this.token,
    this.cardDetails,
    this.errorCode,
    this.errorMessage,
  });

  factory CardTokenResult.success(String token, CardDetails cardDetails) {
    return CardTokenResult(success: true, token: token, cardDetails: cardDetails);
  }

  factory CardTokenResult.failure(String errorCode, String errorMessage) {
    return CardTokenResult(
      success: false,
      errorCode: errorCode,
      errorMessage: errorMessage,
    );
  }
}

